#include <bits/stdc++.h>
using namespace std;
int m,dp[100005];
int main(){
    memset(dp,127,sizeof(dp));
    dp[0]=0;
    scanf("%d",&m);
    for(int i=1;i<=m;i++)
        for(int j=1;j*j*j*j<=i;j++)
            dp[i]=min(dp[i],dp[i-j*j*j*j]+1);
    printf("%d",dp[m]);
    return 0;
}
